import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects',[]):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks',[]):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages',[]):
                key = (name, tfm, pkg['id'])
                pkgs[key] = pkg['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
